const body = $input.first().json.body;
const { events, templateBody, empresa } = typeof body === 'string' ? JSON.parse(body) : body;

function buildMsg(tpl, ev, emp) {
  const d = new Date(ev.date + 'T00:00:00');
  const today = new Date(); today.setHours(0,0,0,0);
  const days = Math.round((d - today) / 86400000);
  return tpl
    .replace(/{{nombre}}/g, ev.contact || 'Cliente')
    .replace(/{{empresa}}/g, emp || 'Mega Sostenible SAC')
    .replace(/{{monto}}/g, parseFloat(ev.amount || 0).toFixed(2))
    .replace(/{{moneda}}/g, ev.currency || 'S/')
    .replace(/{{fecha_venc}}/g, d.toLocaleDateString('es-PE'))
    .replace(/{{num_factura}}/g, ev.title)
    .replace(/{{concepto}}/g, ev.title)
    .replace(/{{dias_restantes}}/g, Math.max(0, days));
}

return events.map(ev => ({
  json: {
    eventId: ev.id,
    phone: (ev.phone || '').replace(/\D/g,''),
    message: buildMsg(templateBody, ev, empresa)
  }
}));
